		H_{\xi\xi}=\operatorname{Hess}_x L(\bar{x}, \bar{y}) + Dg(\bar{x})^* G\, \operatorname{grad} g(\bar{x}) \quad \text{for some} \quad G \in \overline{\nabla}^2 \operatorname{env}_{\rho}\theta\left(g(\bar{x}) + \rho^{-1} \bar{y}\right).
	\end{equation*}
	If $\theta$ is a polyhedral convex function, then the manifold strong variational sufficient condition is equivalent to the following  M-SSOSC at $(\bar{x}, \bar{y})$:
	\begin{equation*}
		\left\langle \xi, \operatorname{Hess}_x L(\bar{x}, \bar{y}) \xi \right\rangle > 0 \quad \forall\, Dg(\bar{x})\xi \in \operatorname{aff}\mathcal{C}_{\theta, g}(\bar{x}, \bar{y}) \setminus \{0\}.
	\end{equation*}
